// ✓ Correct — return a cleanup function
useEffect(() => {
  const id = setInterval(tick, 1000);
  return () => clearInterval(id); // cleanup
}, []);

// ✓ Correct — no cleanup needed (return nothing)
useEffect(() => {
  document.title = title;
}, [title]);

// ✗ Wrong — async function returns a Promise, not a cleanup function
useEffect(async () => {
  const data = await fetchData(); // the implicit return is a Promise
  setData(data);
}, []);

useEffect(() => {
  let cancelled = false;

  async function load() {
    const data = await fetchData();
    if (!cancelled) setData(data);
  }
  load();

  return () => { cancelled = true; }; // cleanup
}, []);

function Modal({ onClose }) {
  useEffect(() => {
    function handleEsc(e) {
      if (e.key === 'Escape') onClose();
    }
    document.addEventListener('keydown', handleEsc);
    return () => document.removeEventListener('keydown', handleEsc);
  }, [onClose]);

  return <dialog>...</dialog>;
}

// When <Modal> is removed:
// → cleanup fires → removeEventListener called → no memory leak

function ChatRoom({ roomId }) {
  useEffect(() => {
    const socket = openSocket(roomId);
    socket.subscribe();

    return () => socket.disconnect(); // cleanup for this roomId
  }, [roomId]);
  // ...
}

// Render 1: roomId = 'general'
//   → openSocket('general'), subscribe
// Render 2: roomId = 'react'
//   → cleanup('general') fires → socket('general').disconnect()
//   → openSocket('react'), subscribe
// Each roomId has exactly one active connection at a time.

// Strict Mode execution order (development only):
// 1. mount → effect runs
// 2. unmount → cleanup runs
// 3. remount → effect runs again

// If your UI looks broken after step 3, check that cleanup
// fully reverses what the effect did in step 1.

useEffect(() => {
  const timerId = setTimeout(() => setVisible(false), 3000);
  return () => clearTimeout(timerId);
}, []);

useEffect(() => {
  const intervalId = setInterval(() => setTick(t => t + 1), 1000);
  return () => clearInterval(intervalId);
}, []);

useEffect(() => {
  function handleResize() {
    setWidth(window.innerWidth);
  }
  window.addEventListener('resize', handleResize);
  handleResize(); // run once immediately to capture current size
  return () => window.removeEventListener('resize', handleResize);
}, []);

// Pattern: the same function reference is used for add and remove.
// Defining handleResize outside the addEventListener call makes this reliable.

useEffect(() => {
  const controller = new AbortController();

  fetch(`/api/posts/${postId}`, { signal: controller.signal })
    .then(r => r.json())
    .then(data => setPost(data))
    .catch(err => {
      if (err.name !== 'AbortError') setError(err);
    });

  return () => controller.abort();
}, [postId]);

// If postId changes before the fetch completes:
// → cleanup calls controller.abort() → fetch is cancelled
// → new fetch starts with the new postId
// → no race condition; only the latest fetch can update state

