const onCloseRef = useRef(onClose);
useEffect(() => { onCloseRef.current = onClose; }); // keep ref current

useEffect(() => {
  const id = setTimeout(() => onCloseRef.current(), 5000);
  return () => clearTimeout(id);
}, []); // empty deps because we read the latest via the ref

import { render, act } from '@testing-library/react';

it('clears the interval on unmount', () => {
  jest.useFakeTimers();
  const { unmount } = render(<Clock />);

  act(() => jest.advanceTimersByTime(3000));
  expect(tickCount).toBe(3);

  unmount(); // triggers cleanup → clearInterval

  act(() => jest.advanceTimersByTime(2000));
  expect(tickCount).toBe(3); // counter did not advance after unmount
});

