// Custom hook encapsulates both subscription and cleanup
function useWindowSize() {
  const [size, setSize] = useState({
    width: window.innerWidth,
    height: window.innerHeight,
  });

  useEffect(() => {
    function handle() {
      setSize({ width: window.innerWidth, height: window.innerHeight });
    }
    window.addEventListener('resize', handle);
    return () => window.removeEventListener('resize', handle);
  }, []);

  return size;
}

// Caller: no cleanup needed — the hook owns it
function Layout() {
  const { width } = useWindowSize();
  return <p>Width: {width}px</p>;
}

function Dashboard({ userId, theme, locale }) {
  // Slot 0: data-fetching effect
  useEffect(() => {
    const ctrl = new AbortController();
    fetchUser(userId, ctrl.signal).then(setUser);
    return () => ctrl.abort(); // slot 0 cleanup
  }, [userId]);

  // Slot 1: theme effect
  useEffect(() => {
    document.body.dataset.theme = theme;
    return () => { delete document.body.dataset.theme; }; // slot 1 cleanup
  }, [theme]);

  // Slot 2: locale effect (no cleanup needed)
  useEffect(() => {
    i18n.setLocale(locale);
  }, [locale]);
}

// When userId changes: only slot 0 cleanup+rerun fires
// When theme changes: only slot 1 cleanup+rerun fires
// Slots 1 and 2 are not disturbed by a userId change

// Component tree: <App> → <Dashboard> → <Widget>

// Mount order (parent first):
//  App effect runs
//  Dashboard effect runs
//  Widget effect runs

// Unmount cleanup order (child first):
//  Widget cleanup runs
//  Dashboard cleanup runs
//  App cleanup runs

// Practical consequence: if Dashboard teardown closes a shared context,
// Widget teardown has already released its reference to that context safely.
